generated_oml:
// Component representing the Digital Shadow
instance DigitalShadow : DTDFVocab:Component [
    base:desc "Digital Shadow encompassing engineering, simulation, and data-calculation components for the first rotary axis of the MABI MAX100 robot."
]

//-----------------------------------------------------------
// Physical Sensing Components
//-----------------------------------------------------------
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current (I_M) sensor providing current time‑series data."
    DTDFVocab:producedData MotorCurrentMQTT
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor encoder sensor providing motor angle time‑series data."
    DTDFVocab:producedData MotorEncoderMQTT
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Gearbox encoder sensor providing gearbox angle time‑series data."
    DTDFVocab:producedData GearboxEncoderMQTT
]

//-----------------------------------------------------------
// Data Transmitted (over MQTT)
//-----------------------------------------------------------
instance MotorCurrentMQTT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorEncoderMQTT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearboxEncoderMQTT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

//-----------------------------------------------------------
// Data Instances
//-----------------------------------------------------------
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Stream of motor current values transmitted over MQTT."
    DTDFVocab:inputTo SimulinkEngine
    DTDFVocab:fromData MotorCurrentMQTT
]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Stream of motor angle values transmitted over MQTT."
    DTDFVocab:inputTo SimulinkEngine
    DTDFVocab:fromData MotorEncoderMQTT
]

instance GearboxAngleData : DTDFVocab:Data [
    base:desc "Stream of gearbox angle values transmitted over MQTT."
    DTDFVocab:inputTo SimulinkEngine
    DTDFVocab:fromData GearboxEncoderMQTT
]

//-----------------------------------------------------------
// Models
//-----------------------------------------------------------
instance EngineeringModel : DTDFVocab:Model [
    base:desc "SysML-based engineering model of the first rotary axis (base joint) of the MABI MAX100 robot."
    DTDFVocab:inputTo SimulinkEngine
]

instance MotorSimulinkBlock : DTDFVocab:Model [
    base:desc "Simulink block representing the permanent‑magnet synchronous motor with Coulomb, Visous, Stribeck, Dahl, and LuGre friction models."
    DTDFVocab:inputTo SimulinkEngine
]

instance GearboxSimulinkBlock : DTDFVocab:Model [
    base:desc "Simulink block representing the dual‑stage cycloidal gearbox."
    DTDFVocab:inputTo SimulinkEngine
]

instance SystemSimulinkBlock : DTDFVocab:Model [
    base:desc "Simulink block combining motor and gearbox models to simulate overall axis behavior."
    DTDFVocab:inputTo SimulinkEngine
]

instance WhiteBoxBaselineModel : DTDFVocab:Model [
    base:desc "White‑box baseline simulation model with frictionless assumption."
    DTDFVocab:inputTo SimulinkEngine
]

instance BlackBoxFrictionModel : DTDFVocab:Model [
    base:desc "Black‑box simulation model for empirical friction representation."
    DTDFVocab:inputTo SimulinkEngine
]

//-----------------------------------------------------------
// Enablers
//-----------------------------------------------------------
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker streaming raw sensor data to the Digital Shadow."
    DTDFVocab:enables RealTimeVisualizationService, ContinuousIdentificationService, ExportFrictionParametersService, WebDashboardService
]

instance SimulinkEngine : DTDFVocab:Enabler [
    base:desc "MathWorks Simulink engine executing friction and drive models."
    DTDFVocab:enables RealTimeVisualizationService, ContinuousIdentificationService, ExportFrictionParametersService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell describing metadata and asset configuration."
]

//-----------------------------------------------------------
// Services
//-----------------------------------------------------------
instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Real‑time visualization of measured vs simulated torque and velocity."
    DTDFVocab:provides MeasuredVsSimulatedTorqueInsight, MeasuredVsSimulatedVelocityInsight
]

instance ContinuousIdentificationService : DTDFVocab:Service [
    base:desc "Continuous identification of friction model parameters."
    DTDFVocab:provides FrictionParameterTrendInsight, ModelDataDiscrepancyInsight, WearIndicatorInsight
]

instance ExportFrictionParametersService : DTDFVocab:Service [
    base:desc "Exports identified friction parameters for controller tuning."
    DTDFVocab:provides ExportFrictionParametersAction
]

instance WebDashboardService : DTDFVocab:Service [
    base:desc "Web‑based dashboard aggregating all data traces."
    DTDFVocab:provides DashboardDataInsight
]

//-----------------------------------------------------------
// Insights
//-----------------------------------------------------------
instance MeasuredVsSimulatedTorqueInsight : DTDFVocab:Insight [
    base:desc "Insight on differences between measured and simulated torque."
]

instance MeasuredVsSimulatedVelocityInsight : DTDFVocab:Insight [
    base:desc "Insight on differences between measured and simulated velocity."
]

instance FrictionParameterTrendInsight : DTDFVocab:Insight [
    base:desc "Insight on trends in the identified friction coefficient."
]

instance ModelDataDiscrepancyInsight : DTDFVocab:Insight [
    base:desc "Insight on discrepancies between model predictions and actual data."
]

instance WearIndicatorInsight : DTDFVocab:Insight [
    base:desc "Insight on wear indicators derived from friction model parameters."
]

instance DashboardDataInsight : DTDFVocab:Insight [
    base:desc "Insight from aggregated data traces displayed on the web dashboard."
]

//-----------------------------------------------------------
// Actions
//-----------------------------------------------------------
instance AdjustControllerParametersAction : DTDFVocab:Action [
    base:desc "Adjusts controller parameters based on updated friction coefficients."
    DTDFVocab:IsAutomatic false
]

instance ScheduleMaintenanceAction : DTDFVocab:Action [
    base:desc "Schedules maintenance when wear indicators exceed threshold."
    DTDFVocab:IsAutomatic false
]

instance ImproveMachiningAccuracyAction : DTDFVocab:Action [
    base:desc "Improves machining accuracy by tuning controller settings without stopping the robot."
    DTDFVocab:IsAutomatic false
]

instance ExportFrictionParametersAction : DTDFVocab:Action [
    base:desc "Automatically exports friction parameters to control system."
    DTDFVocab:IsAutomatic true
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time data ingestion and model identification; the Digital Shadow operates synchronously with the robot’s live data streams."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The Digital Twin constellation consists of: the physical robot first axis, its sensors and controller, an AAS instance to describe the asset, a processing component executing Simulink models, an MQTT broker mediating data streams, and a visualization dashboard; all components are orchestrated through standardized topic naming and AAS references."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The twin covers the design phase (ideal white‑box models), the manufactured phase (sensor installation and AAS metadata), and the operated phase (live data streams used for continuous calibration)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Model fidelity is ensured by traceable mapping between sensor data, derived state, and simulation outputs; validation occurs via comparison of simulated and measured torque/velocity; uncertainty from load, temperature, and wear is addressed by continuously updating the black‑box friction parameters."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Physical data captured via MQTT protocol, with metadata linking to AAS; data traces include source identifiers. No explicit mention of additional network protocols or databases."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Employs Asset Administration Shell (AAS) aligning with Industry 4.0, SysML modeling, and MQTT communication, following common industrial IoT and modeling standards."
]
